// Solution
int Solution::binarySearch(vector<int>& arr, int target) {
    if (arr.size() == 0) return -1;
    int left = 0, right = arr.size() - 1;
    while (left <= right) {
        int mid = (left + right) / 2;
        if (arr[mid] == target) return mid;
        right = mid - 1;
    }
    return -1;
}

